const Redis = global.get('redis');
const { manufacturer, serialNumber, topicSuffix, body } = msg.payload;

if (!manufacturer || !serialNumber || !topicSuffix) {
    node.error('Missing required fields: manufacturer, serialNumber, topicSuffix');
    return null;
}

const topic = `vda5050/${manufacturer}/${serialNumber}/${topicSuffix}`;

// Build VDA5050 message with header
const message = {
    headerId: Date.now(),
    timestamp: new Date().toISOString(),
    version: '2.0.0',
    manufacturer: manufacturer,
    serialNumber: serialNumber,
    ...body
};

msg.topic = topic;
msg.payload = message;
msg.qos = 1;
msg.retain = (topicSuffix === 'connection');
return msg;
